insert  into `activity`(`id`,`title`,`content`,`oper_time`,`communityid`,`img`) values 
(2,'清明时节，一起踏青！','亲爱的居民朋友们：\n清明时节，春意渐浓，草木萌新。为丰富社区文化生活，舒缓身心，感受春日美好，社区特组织清明踏青活动，诚邀各位居民结伴同行，共赏春色、共话邻里情。\n一、活动主题\n清明踏青・亲近自然・和睦邻里\n二、活动地点\n公园 / 绿地（具体以通知为准）\n三、活动内容\n春日漫步，欣赏自然风光，感受清明节气氛围\n邻里交流，分享生活趣事，增进邻里情谊\n文明踏青，爱护环境，文明出游\n五、温馨提示\n请穿着舒适衣物与运动鞋，根据天气携带防晒、雨具等物品。\n活动期间听从工作人员安排，注意出行安全，照看好老人与小孩。\n文明踏青，不攀折花木、不乱扔垃圾，共同守护优美环境。\n如遇天气等特殊情况，活动将另行通知。\n清明踏春，不负好时光。期待与您一起走出家门，拥抱春日暖阳，共度温馨美好的社区时光！','2025-10-17',1,'https://news11.oss-cn-chengdu.aliyuncs.com/1775382769749屏幕截图 2026-04-05 175012.png'),
(3,'社区服务功能升级','<p>为了更好地服务社区居民，我们将对便民服务进行全面升级。</p><p><strong>升级内容包括：</strong></p><ul><li>新增在线预约功能</li><li>优化服务流程</li><li>扩大服务范围</li></ul><p>欢迎大家积极参与和体验！</p>','2025-10-17',1,'https://news11.oss-cn-chengdu.aliyuncs.com/1775382521700屏幕截图 2026-04-05 174814.png'),
(4,'限时活动：家政大促销！！！','? 家电焕新，生活更舒心 ?为方便大家添置家电，特推出家电大促活动：种类齐全、价格实惠、质量放心、售后有保障。无论是换新家电，还是装修购置，都能在这里选到心仪好物。优惠不常有，机会别错过！让好家电，守护您的品质生活。','2025-10-31',1,'https://news11.oss-cn-chengdu.aliyuncs.com/177538281760021bc638c73bfcdf2.webp');
