insert  into `notice`(`id`,`title`,`content`,`oper_time`,`communityid`) values 
(2,'新增家政服务，预约更便捷','为满足居民日益增长的家政服务需求，我们新增了专业的家政服务团队。服务内容包括：日常保洁、深度清洁、家电维修、管道疏通等。所有服务人员均经过专业培训和背景审查，服务质量有保障。现可通过小程序在线预约，享受便捷服务。1111','2025-10-17',1),
(3,'代购服务覆盖范围扩大通知','应广大居民要求，代购服务覆盖范围进一步扩大。新增服务区域包括：市中心商圈、各大超市、药店、花店等。配送时间调整为每日8:00-22:00，节假日正常服务。同时优化了配送路线，缩短了配送时间，提升服务效率。','2025-10-17',1);
