(357,'社区活动',1,'com.web.CommunityController.updateActivity()','POST',1,'Lisa','','/api/communityCtl/updateActivity','127.0.0.1','内网IP','{\"content\":\"亲爱的居民朋友们：\\n清明时节，春意渐浓，草木萌新。为丰富社区文化生活，舒缓身心，感受春日美好，社区特组织清明踏青活动，诚邀各位居民结伴同行，共赏春色、共话邻里情。\\n一、活动主题\\n清明踏青・亲近自然・和睦邻里\\n二、活动地点\\n公园 / 绿地（具体以通知为准）\\n三、活动内容\\n春日漫步，欣赏自然风光，感受清明节气氛围\\n邻里交流，分享生活趣事，增进邻里情谊\\n文明踏青，爱护环境，文明出游\\n五、温馨提示\\n请穿着舒适衣物与运动鞋，根据天气携带防晒、雨具等物品。\\n活动期间听从工作人员安排，注意出行安全，照看好老人与小孩。\\n文明踏青，不攀折花木、不乱扔垃圾，共同守护优美环境。\\n如遇天气等特殊情况，活动将另行通知。\\n清明踏春，不负好时光。期待与您一起走出家门，拥抱春日暖阳，共度温馨美好的社区时光！\",\"id\":2,\"img\":\"https://news11.oss-cn-chengdu.aliyuncs.com/1775382769749屏幕截图 2026-04-05 175012.png\",\"operTime\":1760630400000,\"pageNo\":0,\"pageSize\":0,\"title\":\"清明时节，一起踏青！\"}','{\"code\":200,\"data\":{\"content\":\"亲爱的居民朋友们：\\n清明时节，春意渐浓，草木萌新。为丰富社区文化生活，舒缓身心，感受春日美好，社区特组织清明踏青活动，诚邀各位居民结伴同行，共赏春色、共话邻里情。\\n一、活动主题\\n清明踏青・亲近自然・和睦邻里\\n二、活动地点\\n公园 / 绿地（具体以通知为准）\\n三、活动内容\\n春日漫步，欣赏自然风光，感受清明节气氛围\\n邻里交流，分享生活趣事，增进邻里情谊\\n文明踏青，爱护环境，文明出游\\n五、温馨提示\\n请穿着舒适衣物与运动鞋，根据天气携带防晒、雨具等物品。\\n活动期间听从工作人员安排，注意出行安全，照看好老人与小孩。\\n文明踏青，不攀折花木、不乱扔垃圾，共同守护优美环境。\\n如遇天气等特殊情况，活动将另行通知。\\n清明踏春，不负好时光。期待与您一起走出家门，拥抱春日暖阳，共度温馨美好的社区时光！\",\"id\":2,\"img\":\"https://news11.oss-cn-chengdu.aliyuncs.com/1775382769749屏幕截图 2026-04-05 175012.png\",\"operTime\":1760630400000,\"pageNo\":0,\"pageSize\":0,\"title\":\"清明时节，一起踏青！\"},\"message\":\"修改社区活动\"}',0,NULL,'2026-04-17 11:33:31',182),
